#!/bin/bash\n# LearnIQ Local Development Setup Script\n# Run: chmod +x setup-local.sh && ./setup-local.sh\n\necho -e \"\\033[36m🚀 LearnIQ Local Development Setup\\033[0m\"\necho -e \"\\033[36m================================\\033[0m\"\necho \"\"\n\n# Check Node.js\necho -e \"\\033[33mChecking Node.js installation...\\033[0m\"\nif ! command -v node &> /dev/null; then\n    echo -e \"\\033[31m❌ Node.js not found. Please install Node.js first.\\033[0m\"\n    exit 1\nfi\nnode --version\necho -e \"\\033[32m✓ Node.js found\\033[0m\"\necho \"\"\n\n# Check MySQL\necho -e \"\\033[33mChecking MySQL installation...\\033[0m\"\nif ! command -v mysql &> /dev/null; then\n    echo -e \"\\033[33m⚠️  MySQL not found. Make sure MySQL is installed and in PATH.\\033[0m\"\nelse\n    mysql --version\n    echo -e \"\\033[32m✓ MySQL found\\033[0m\"\nfi\necho \"\"\n\n# Setup Frontend\necho -e \"\\033[33mSetting up Frontend...\\033[0m\"\nif [ ! -f \".env.local\" ]; then\n    echo -e \"\\033[90mCreating .env.local...\\033[0m\"\n    cat > .env.local << 'EOF'\nVITE_API_URL=http://localhost:5000/api/v1\nREACT_APP_API_URL=http://localhost:5000/api/v1\nNODE_ENV=development\nVITE_DEBUG=true\nVITE_SERVICE_WORKER_ENABLED=true\nVITE_OFFLINE_MODE=true\nEOF\n    echo -e \"\\033[32m✓ .env.local created\\033[0m\"\nelse\n    echo -e \"\\033[32m✓ .env.local already exists\\033[0m\"\nfi\n\nif [ ! -d \"node_modules\" ]; then\n    echo -e \"\\033[90mInstalling frontend dependencies...\\033[0m\"\n    npm install\n    echo -e \"\\033[32m✓ Frontend dependencies installed\\033[0m\"\nelse\n    echo -e \"\\033[32m✓ Frontend dependencies already installed\\033[0m\"\nfi\necho \"\"\n\n# Setup Backend\necho -e \"\\033[33mSetting up Backend...\\033[0m\"\nif [ ! -f \"backend/.env.local\" ]; then\n    echo -e \"\\033[90mCreating backend/.env.local...\\033[0m\"\n    cat > backend/.env.local << 'EOF'\nPORT=5000\nNODE_ENV=development\nDB_HOST=localhost\nDB_USER=root\nDB_PASSWORD=password\nDB_DATABASE=pwa_let_db\nDB_PORT=3306\nJWT_SECRET=your_super_secret_jwt_key_change_this_in_production\nCORS_ORIGIN=http://localhost:3000,http://localhost:5173,http://127.0.0.1:3000\nAPI_PREFIX=/api/v1\nFRONTEND_URL=http://localhost:3000\nEOF\n    echo -e \"\\033[32m✓ backend/.env.local created\\033[0m\"\nelse\n    echo -e \"\\033[32m✓ backend/.env.local already exists\\033[0m\"\nfi\n\nif [ ! -d \"backend/node_modules\" ]; then\n    echo -e \"\\033[90mInstalling backend dependencies...\\033[0m\"\n    cd backend\n    npm install\n    cd ..\n    echo -e \"\\033[32m✓ Backend dependencies installed\\033[0m\"\nelse\n    echo -e \"\\033[32m✓ Backend dependencies already installed\\033[0m\"\nfi\necho \"\"\n\n# Database setup\necho -e \"\\033[33mDatabase Setup\\033[0m\"\necho -e \"\\033[90mImportant: Make sure MySQL is running before continuing.\\033[0m\"\necho -e \"\\033[90mTo run migrations and seed data, execute:\\033[0m\"\necho -e \"\\033[36m  cd backend\\033[0m\"\necho -e \"\\033[36m  npm run migrate\\033[0m\"\necho -e \"\\033[36m  npm run seed\\033[0m\"\necho \"\"\n\n# Final instructions\necho -e \"\\033[32m✅ Setup Complete!\\033[0m\"\necho \"\"\necho -e \"\\033[36mNext Steps:\\033[0m\"\necho -e \"\\033[37m1. Update database credentials in backend/.env.local\\033[0m\"\necho -e \"\\033[37m2. Make sure MySQL is running\\033[0m\"\necho -e \"\\033[37m3. Run database migrations: cd backend && npm run migrate\\033[0m\"\necho -e \"\\033[37m4. Open two terminals and run:\\033[0m\"\necho -e \"\\033[36m   Terminal 1 (Frontend): npm run dev\\033[0m\"\necho -e \"\\033[36m   Terminal 2 (Backend):  cd backend && npm run dev\\033[0m\"\necho -e \"\\033[37m5. Open http://localhost:3000 in your browser\\033[0m\"\necho \"\"\necho -e \"\\033[90mFor more help, see DEPLOYMENT_GUIDE_COMPLETE.md\\033[0m\"\n